refentry.refsect1:
&reftitle.description;

 voidgmp_setbit
 GMPnum
 intindex
 boolvalue&true;



 Imposta il bit index in num.

  &reftitle.examples;



    Esempio di gmp_setbit - indice 0


<?php
$a = gmp_init("2"); //
echo gmp_strval($a), ' -> 0b', gmp_strval($a, 2), "\n";
gmp_setbit($a, 0); // 0b10 diventa 0b11
echo gmp_strval($a), ' -> 0b', gmp_strval($a, 2), "\n";
?>


    &example.outputs;


2 -> 0b10
3 -> 0b11





    Esempio di gmp_setbit - indice 1


<?php
$a = gmp_init("0xfd");
echo gmp_strval($a), ' -> 0b', gmp_strval($a, 2), "\n";
gmp_setbit($a, 1); // l'indice parte da 0
echo gmp_strval($a), ' -> 0b', gmp_strval($a, 2), "\n";
?>


    &example.outputs;


253 -> 0b11111101
255 -> 0b11111111





    Esempio di gmp_setbit - azzerare un bit


<?php
$a = gmp_init("0xff");
echo gmp_strval($a), ' -> 0b', gmp_strval($a, 2), "\n";
gmp_setbit($a, 0, false); // azzera il bit all'indice 0
echo gmp_strval($a), ' -> 0b', gmp_strval($a, 2), "\n";
?>


    &example.outputs;


255 -> 0b11111111
254 -> 0b11111110
